// ============================================================
// FILE UPLOAD COMPONENT
// ============================================================
function FileUpload({ accept, onFileSelect, fileType, icon }) {
  const [dragOver, setDragOver] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) {
      setSelectedFile(file);
      onFileSelect(file);
    }
  }, [onFileSelect]);

  const handleChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setSelectedFile(file);
      onFileSelect(file);
    }
  };

  return (
    <div
      className={`file-upload ${dragOver ? 'drag-over' : ''} ${selectedFile ? 'has-file' : ''}`}
      onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
      onDragLeave={() => setDragOver(false)}
      onDrop={handleDrop}
    >
      <input
        type="file"
        accept={accept}
        onChange={handleChange}
        id={`file-${fileType}`}
        hidden
      />
      <label htmlFor={`file-${fileType}`} className="upload-label">
        {selectedFile ? (
          <>
            <div className="upload-success-icon"><Icons.Check /></div>
            <span className="upload-filename">{selectedFile.name}</span>
            <span className="upload-size">{(selectedFile.size / (1024 * 1024)).toFixed(2)} MB</span>
          </>
        ) : (
          <>
            <div className="upload-icon">{icon}</div>
            <span className="upload-text">Drop your {fileType} file here</span>
            <span className="upload-subtext">or click to browse</span>
            <span className="upload-formats">Supported: {accept}</span>
          </>
        )}
      </label>
    </div>
  );
}


// ============================================================
// RISK SCORE GAUGE
// ============================================================
function RiskGauge({ score, label, size = 120 }) {
  const radius = (size - 20) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (score / 100) * circumference;

  const getColor = (s) => {
    if (s <= 30) return '#10b981';
    if (s <= 50) return '#f59e0b';
    if (s <= 70) return '#f97316';
    return '#ef4444';
  };

  const getLevel = (s) => {
    if (s <= 30) return 'Minimal';
    if (s <= 50) return 'Low';
    if (s <= 70) return 'Moderate';
    return 'High';
  };

  return (
    <div className="risk-gauge">
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <circle
          cx={size/2} cy={size/2} r={radius}
          fill="none" stroke="rgba(255,255,255,0.08)" strokeWidth="8"
        />
        <circle
          cx={size/2} cy={size/2} r={radius}
          fill="none" stroke={getColor(score)} strokeWidth="8"
          strokeDasharray={circumference} strokeDashoffset={offset}
          strokeLinecap="round"
          transform={`rotate(-90 ${size/2} ${size/2})`}
          style={{ transition: 'stroke-dashoffset 1s ease' }}
        />
        <text x={size/2} y={size/2 - 8} textAnchor="middle" fill="white" fontSize="22" fontWeight="700">
          {score}
        </text>
        <text x={size/2} y={size/2 + 12} textAnchor="middle" fill={getColor(score)} fontSize="11" fontWeight="600">
          {getLevel(score)} Risk
        </text>
      </svg>
      <span className="gauge-label">{label}</span>
    </div>
  );
}


