            <div className="form-group full-width">
              <label>Other Neurological Conditions</label>
              <textarea name="familyOtherNeuro" value={formData.familyOtherNeuro} onChange={handleChange} placeholder="List any other neurological conditions in the family..." rows="2" />
            </div>
          </div>

          <div className="form-section">
            <h3>Maternal Health</h3>
            <div className="form-grid">
              <div className="form-group">
                <label>Maternal Age</label>
                <input type="number" name="maternalAge" value={formData.maternalAge} onChange={handleChange} placeholder="e.g., 28" />
              </div>
              <div className="form-group">
                <label>Prenatal Complications</label>
                <input name="prenatalComplications" value={formData.prenatalComplications} onChange={handleChange} placeholder="e.g., gestational diabetes" />
              </div>
              <div className="form-group">
                <label>Medications During Pregnancy</label>
                <input name="prenatalMedications" value={formData.prenatalMedications} onChange={handleChange} placeholder="e.g., prenatal vitamins" />
              </div>
            </div>
          </div>

          {error && <div className="error-message"><Icons.Alert /> {error}</div>}

          <div className="card-actions">
            <button className="btn-primary" onClick={handleSubmit}>
              <Icons.Brain /> Analyze Health Data
            </button>
          </div>
        </div>
      )}

      {loading && <LoadingAnalysis message="Analyzing health data with Predictive AI..." />}

      {result && (
        <div className="results-container">
          <div className="result-header">
            <h2>Health Data Analysis Results</h2>
            <RiskGauge score={result.overall_risk_score || 35} label="Overall Risk" size={140} />
          </div>

          {result.risk_scores && (
            <div className="result-cards-grid">
              {Object.entries(result.risk_scores).map(([key, data]) => (
                <div className="result-detail-card" key={key}>
                  <h3>{key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}</h3>
                  <RiskGauge score={data.score} label="" size={90} />
                  <span className={`risk-badge risk-${data.risk_level?.toLowerCase()}`}>
                    {data.risk_level} Risk
                  </span>
                  {data.factors?.length > 0 && (
                    <div className="concerns">
                      <h4>Factors:</h4>
                      {data.factors.map((f, i) => <span key={i} className="concern-tag">{f}</span>)}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

          {result.recommendations && (
            <div className="summary-card">
              <h3>Recommendations</h3>
              <div className="recommendation-list">
                {result.recommendations.map((r, i) => (
                  <div key={i} className="recommendation-item">
                    <Icons.Check /> <span>{r}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {result.summary && (
            <div className="summary-card">
              <h3>Summary</h3>
              <p>{result.summary}</p>
            </div>
          )}

          <div className="card-actions">
            <button className="btn-secondary" onClick={() => { setResult(null); }}>
              Edit Health Data
            </button>
            <button className="btn-primary" onClick={() => navigate('/results')}>
              View Comprehensive Results →
            </button>
          </div>
        </div>
      )}
    </div>
  );
}


// ============================================================
// COMPREHENSIVE RESULTS PAGE
// ============================================================
function Results({ videoResult, audioResult, healthResult }) {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const hasData = videoResult || audioResult || healthResult;

  const generateComprehensive = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await axios.post(`${API_URL}/api/analyze/comprehensive`, {
        videoAnalysis: videoResult || {},
        audioAnalysis: audioResult || {},
        healthAnalysis: healthResult || {},
      }, { timeout: 60000 });
      setResult(response.data.analysis);
    } catch (err) {
      setError(err.response?.data?.error || 'Analysis failed. Please try again.');
    }
    setLoading(false);
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h1><Icons.Chart /> Comprehensive Assessment</h1>
          <p className="subtitle">Combined AI analysis from all screening modules</p>
        </div>
      </div>

      {!result && !loading && (
        <div className="analysis-card">
          <h3>Data Collection Status</h3>
          <div className="status-grid">
            <div className={`status-item ${videoResult ? 'complete' : 'pending'}`}>
              <Icons.Video />
              <span>Video Analysis</span>
              <span className="status-badge">{videoResult ? '✓ Complete' : '○ Pending'}</span>
            </div>
            <div className={`status-item ${audioResult ? 'complete' : 'pending'}`}>
              <Icons.Audio />
              <span>Audio Analysis</span>
              <span className="status-badge">{audioResult ? '✓ Complete' : '○ Pending'}</span>
            </div>
            <div className={`status-item ${healthResult ? 'complete' : 'pending'}`}>
              <Icons.Clipboard />
              <span>Health Data</span>
              <span className="status-badge">{healthResult ? '✓ Complete' : '○ Pending'}</span>
            </div>
          </div>

          {!hasData && (
            <div className="info-box" style={{ marginTop: '24px' }}>
              <h4>No data collected yet</h4>
              <p>Please complete at least one screening module (Video, Audio, or Health Data) before generating a comprehensive assessment.</p>
            </div>
          )}

          {error && <div className="error-message"><Icons.Alert /> {error}</div>}

          <div className="card-actions">
            <button className="btn-primary" onClick={generateComprehensive} disabled={!hasData}>
              <Icons.Brain /> Generate Comprehensive Assessment
            </button>
          </div>
        </div>
      )}

      {loading && <LoadingAnalysis message="Generating comprehensive assessment..." />}

      {result && (
        <div className="results-container comprehensive-results">
          <div className="result-header">
            <h2>NeoMind Comprehensive Assessment</h2>
            {result.overall_assessment && (
              <RiskGauge score={result.overall_assessment.risk_score} label="Overall Risk" size={160} />
            )}
          </div>

          {result.comprehensive_scores && (
            <>
              <h3 className="section-heading">Disorder Risk Scores</h3>
              <div className="result-cards-grid">
                {Object.entries(result.comprehensive_scores).map(([key, data]) => (
                  <div className="result-detail-card" key={key}>
                    <h3>{key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}</h3>
                    <RiskGauge score={data.score} label="" size={100} />
                    <span className={`risk-badge risk-${data.level?.toLowerCase()}`}>
                      {data.level} Risk
                    </span>
                    <div className="confidence">Confidence: {data.confidence}%</div>
                    {data.key_indicators?.length > 0 && (
                      <div className="concerns">
                        <h4>Key Indicators:</h4>
                        {data.key_indicators.map((ind, i) => <span key={i} className="concern-tag">{ind}</span>)}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </>
          )}

          {result.intervention_plan && (
            <div className="intervention-section">
              <h3 className="section-heading">Intervention Plan</h3>
              <div className="intervention-grid">
                {result.intervention_plan.immediate_actions?.length > 0 && (
                  <div className="intervention-card urgent">
                    <h4>⚡ Immediate Actions</h4>
                    {result.intervention_plan.immediate_actions.map((a, i) => (
                      <div key={i} className="recommendation-item"><Icons.Alert /> <span>{a}</span></div>
                    ))}
                  </div>
                )}
                {result.intervention_plan.short_term?.length > 0 && (
                  <div className="intervention-card">
                    <h4>📅 Short-Term (1-3 months)</h4>
                    {result.intervention_plan.short_term.map((a, i) => (
                      <div key={i} className="recommendation-item"><Icons.Check /> <span>{a}</span></div>
                    ))}
                  </div>
                )}
                {result.intervention_plan.long_term?.length > 0 && (
                  <div className="intervention-card">
                    <h4>📆 Long-Term (6-12 months)</h4>
                    {result.intervention_plan.long_term.map((a, i) => (
                      <div key={i} className="recommendation-item"><Icons.Check /> <span>{a}</span></div>
                    ))}
                  </div>
                )}
                {result.intervention_plan.therapy_suggestions?.length > 0 && (
                  <div className="intervention-card">
                    <h4>🩺 Therapy Suggestions</h4>
                    {result.intervention_plan.therapy_suggestions.map((a, i) => (
                      <div key={i} className="recommendation-item"><Icons.Check /> <span>{a}</span></div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {result.medical_followup && (
            <div className="summary-card">
              <h3>Medical Follow-Up</h3>
              {result.medical_followup.specialists?.length > 0 && (
                <div className="followup-section">
                  <h4>Recommended Specialists:</h4>
                  <div className="tag-list">
                    {result.medical_followup.specialists.map((s, i) => <span key={i} className="specialist-tag">{s}</span>)}
                  </div>
                </div>
              )}
              {result.medical_followup.tests?.length > 0 && (
                <div className="followup-section">
                  <h4>Recommended Tests:</h4>
                  <div className="tag-list">
                    {result.medical_followup.tests.map((t, i) => <span key={i} className="test-tag">{t}</span>)}
                  </div>
                </div>
              )}
              {result.medical_followup.timeline && (
                <p className="timeline-text"><strong>Timeline:</strong> {result.medical_followup.timeline}</p>
              )}
            </div>
          )}

          {result.overall_assessment?.summary && (
            <div className="summary-card highlight">
              <h3>Overall Assessment Summary</h3>
              <p>{result.overall_assessment.summary}</p>
            </div>
          )}

          <div className="disclaimer-banner">
            <Icons.Alert />
            <p>{result.disclaimer || 'This AI assessment is for screening purposes only. It does not constitute a medical diagnosis. Please consult qualified healthcare professionals for proper evaluation.'}</p>
          </div>

          <div className="card-actions">
            <button className="btn-secondary" onClick={() => setResult(null)}>
              Re-generate Assessment
            </button>
            <button className="btn-primary" onClick={() => window.print()}>
              Print Report
            </button>
          </div>
        </div>
      )}
    </div>
  );
}


// ============================================================
// MAIN APP
// ============================================================
function App() {
  const [videoResult, setVideoResult] = useState(null);
  const [audioResult, setAudioResult] = useState(null);
  const [healthResult, setHealthResult] = useState(null);

  return (
    <Router>
      <div className="app">
        <Sidebar />
        <main className="main-content">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/video" element={<VideoAnalysis onResult={setVideoResult} />} />
            <Route path="/audio" element={<AudioAnalysis onResult={setAudioResult} />} />
            <Route path="/health" element={<HealthData onResult={setHealthResult} />} />
            <Route path="/results" element={
              <Results videoResult={videoResult} audioResult={audioResult} healthResult={healthResult} />
            } />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;
